INSERT INTO `his_config_info` (`id`, `nid`, `data_id`, `group_id`, `app_name`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `op_type`, `tenant_id`, `encrypted_data_key`, `publish_type`, `gray_name`, `ext_info`) VALUES (2, 30, 'ruoyi-gateway-dev.yml', 'DEFAULT_GROUP', '', 'spring:\n  redis:\n    host: 127.0.0.1\n    port: 6379\n    password: easdj#2zz$834=\n  cloud:\n    gateway:\n      discovery:\n        locator:\n          lowerCaseServiceId: true\n          enabled: true\n      routes:\n        # 认证中心\n        - id: ruoyi-auth\n          uri: lb://ruoyi-auth\n          predicates:\n            - Path=/auth/**\n          filters:\n            # 验证码处理\n            - CacheRequestFilter\n            - ValidateCodeFilter\n            - StripPrefix=1\n        # 代码生成\n        - id: ruoyi-gen\n          uri: lb://ruoyi-gen\n          predicates:\n            - Path=/code/**\n          filters:\n            - StripPrefix=1\n        # 定时任务\n        - id: ruoyi-job\n          uri: lb://ruoyi-job\n          predicates:\n            - Path=/schedule/**\n          filters:\n            - StripPrefix=1\n        # 系统模块\n        - id: ruoyi-system\n          uri: lb://ruoyi-system\n          predicates:\n            - Path=/system/**\n          filters:\n            - StripPrefix=1\n        # 文件服务\n        - id: ruoyi-file\n          uri: lb://ruoyi-file\n          predicates:\n            - Path=/file/**\n          filters:\n            - StripPrefix=1\n        # 广告工具服务\n        - id: ruoyi-adm\n          uri: lb://ruoyi-adm\n          predicates:\n            - Path=/adm/**\n          filters:\n            - StripPrefix=1\n        # 落地页服务\n        - id: ruoyi-landing\n          uri: lb://ruoyi-landing\n          predicates:\n            - Path=/landing/**\n          filters:\n            - StripPrefix=1\n\n# 安全配置\nsecurity:\n  # 验证码\n  captcha:\n    enabled: true\n    type: math\n  # 防止XSS攻击\n  xss:\n    enabled: true\n    excludeUrls:\n      - /system/notice\n\n  # 不校验白名单\n  ignore:\n    whites:\n      - /auth/logout\n      - /auth/login\n      - /auth/register\n      - /*/v2/api-docs\n      - /*/v3/api-docs\n      - /csrf\n\n# springdoc配置\nspringdoc:\n  webjars:\n    # 访问前缀\n    prefix:\n', 'ef617409165617782b23b7a1dee9e0b3', '2025-04-14 01:34:32', '2025-04-14 01:34:33', NULL, '113.246.61.47', 'U', '', '', 'formal', NULL, NULL);
INSERT INTO `his_config_info` (`id`, `nid`, `data_id`, `group_id`, `app_name`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `op_type`, `tenant_id`, `encrypted_data_key`, `publish_type`, `gray_name`, `ext_info`) VALUES (35, 31, 'ruoyi-landing-web-dev.yml', 'DEFAULT_GROUP', '', '# Spring配置\nspring:\n  mvc:\n    pathmatch:\n      matching-strategy: ant_path_matcher\n  # 模板引擎\n  thymeleaf:\n    mode: HTML\n    encoding: utf-8\n    # 禁用缓存\n    cache: false\n  # 资源信息\n  messages:\n    # 国际化资源文件路径\n    basename: static/i18n/messages\n  jackson:\n    time-zone: GMT+8\n    date-format: yyyy-MM-dd HH:mm:ss\n  profiles:\n    active: druid\n  # 服务模块\n  devtools:\n    restart:\n      # 热部署开关\n      enabled: true\n  tomcat:\n    # tomcat的URI编码\n    uri-encoding: UTF-8\n    # 连接数满后的排队数，默认为100\n    accept-count: 1000\n    threads:\n      # tomcat最大线程数，默认为200\n      max: 800\n      # Tomcat启动初始化的线程数，默认值10\n      min-spare: 100\n    relaxed-query-chars: [ \'{\',\'}\' ]', '7113e6b6a89ec153d7114746055717bf', '2025-04-14 10:08:34', '2025-04-14 10:08:35', NULL, '113.246.61.101', 'U', '', '', 'formal', NULL, NULL);
INSERT INTO `his_config_info` (`id`, `nid`, `data_id`, `group_id`, `app_name`, `content`, `md5`, `gmt_create`, `gmt_modified`, `src_user`, `src_ip`, `op_type`, `tenant_id`, `encrypted_data_key`, `publish_type`, `gray_name`, `ext_info`) VALUES (35, 32, 'ruoyi-landing-web-dev.yml', 'DEFAULT_GROUP', '', '# Spring配置\nspring:\n  mvc:\n    pathmatch:\n      matching-strategy: ant_path_matcher\n  # 模板引擎\n  thymeleaf:\n    mode: HTML\n    encoding: utf-8\n    # 禁用缓存\n    cache: false\n  # 资源信息\n  messages:\n    # 国际化资源文件路径\n    basename: static/i18n/messages\n  jackson:\n    time-zone: GMT+8\n    date-format: yyyy-MM-dd HH:mm:ss\n  profiles:\n    active: druid\n  # 服务模块\n  devtools:\n    restart:\n      # 热部署开关\n      enabled: true\nserver:\n  tomcat:\n    # tomcat的URI编码\n    uri-encoding: UTF-8\n    # 连接数满后的排队数，默认为100\n    accept-count: 1000\n    threads:\n      # tomcat最大线程数，默认为200\n      max: 800\n      # Tomcat启动初始化的线程数，默认值10\n      min-spare: 100\n    relaxed-query-chars: [ \'{\',\'}\' ]', 'e9177249db2701073c70b037e2f17761', '2025-04-14 10:09:37', '2025-04-14 10:09:38', NULL, '113.246.61.101', 'U', '', '', 'formal', NULL, NULL);
